query:
CREATE TABLE IF NOT EXISTS terminal_messages (
  id VARCHAR(36) PRIMARY KEY,
  session_id VARCHAR(36) NOT NULL REFERENCES terminal_sessions(id) ON DELETE CASCADE,
  role VARCHAR(20) NOT NULL,
  content TEXT NOT NULL,
  citations JSON DEFAULT '[]',
  suggested_actions JSON DEFAULT '[]',
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);

CREATE INDEX IF NOT EXISTS idx_terminal_messages_session_id ON terminal_messages(session_id);
CREATE INDEX IF NOT EXISTS idx_terminal_messages_created_at ON terminal_messages(created_at);

